from sys import stdin
from collections import deque

class Solution:
    def deleteMiddleElement(self, head, val):
        if not head:
            return head
        if head.val == val:
            return self.deleteMiddle(head)
        prev = head
        while prev.next and prev.val != val:
            prev = prev.next
        prev.next = self.deleteMiddle(prev.next)
        return head

    def deleteMiddle(self, head):
        if not head or not head.next:
            return head
        head = head.next
        return head

    def get_list(self, line):
        line = line.strip()
        arr = list(map(int, line.split()))
        head = ListNode(arr[0])
        curr = head
        for num in arr[1::]:
            curr.next = ListNode(num)
            curr = curr.next
        return head

    def print_list(self, head):
        curr = head
        while curr:
            print(curr.val, end=' -> ') if curr.val != 0 else print('0 ->')
            curr = curr.next
        print()

    def read_input(self):
        self.head = self.get_list(stdin.readline().strip())
        val = int(stdin.readline().strip())
        return self.deleteMiddleElement(self.head, val)

    def execute(self):
        self.head = self.read_input()
        self.print_list(self.head)

solution = Solution()

if __name__ == '__main__':
    solution.execute()

class ListNode:
    def __init__(self, val= 0, next=None):
        self.val = val
        self.next = next

