using namespace std;

class Solution {
public:
    struct ListNode {
        int val;
        ListNode *next;
    };

    ListNode* deleteMiddleElement(ListNode* head, int val) {
        if (!head) return head;
        if (head->val == val) return deleteMiddle(head);
        ListNode* prev = head;
        while (prev->next && prev->val != val) prev = prev->next;
        prev->next = deleteMiddle(prev->next);
        return head;
    }

    ListNode* deleteMiddle(ListNode* head) {
        if (!head || !head->next) return head;
        head = head->next;
        return head;
    }

    string read_input(istream& in) {
        string line;
        getline(in, line);
        return line;
    }

    void print_list(ListNode* head) {
        ListNode* curr = head;
        while (curr) {
            cout << curr->val << ' -> ';\n            if (curr->val != 0) {
                curr = curr->next;
            } else {
                cout << '0 ->';\n                break;
            }
        }
        cout << endl;
    }

    void execute() {
        ListNode* head = get_list(read_input(cin));
        int val = stoi(read_input(cin));
        ListNode* res = deleteMiddleElement(head, val);
        print_list(res);
    }

    ListNode* get_list(const string& line) {
        istringstream iss(line);
        int val;
        ListNode* head = nullptr;
        ListNode* curr = nullptr;
        while (iss >> val) {
            if (!head) {
                head = new ListNode(val);
                curr = head;
            } else {
                curr->next = new ListNode(val);
                curr = curr->next;
            }
        }
        return head;
    }
};

